#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=2e1+5;
int n,f[maxn]={0,0,1,2};
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	if(n<4){
		cout<<n-1;
		return 0;
	}
	for(int i=4;i<=n;i++){
		f[i]=(i-1)*(f[i-1]+f[i-2]);
	}
	cout<<f[n];
	return 0;
}
